// Generated by forge proof from tui-view-switcher.md, tui-specs-list.md, tui-spec-detail.md, forge-tui-sessions.md
import { describe, test, expect, afterEach } from 'bun:test';
import { promises as fs } from 'fs';
import path from 'path';
import os from 'os';
import type { SpecManifest, SpecEntry, SpecRun, ForgeResult } from './types.js';
import { loadManifest, saveManifest } from './specs.js';

// ── Helpers ──────────────────────────────────────────────────

let tmpDirs: string[] = [];

async function makeTmpDir(): Promise<string> {
  const raw = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-tui-views-'));
  const dir = await fs.realpath(raw);
  tmpDirs.push(dir);
  return dir;
}

afterEach(async () => {
  for (const d of tmpDirs) {
    await fs.rm(d, { recursive: true, force: true }).catch(() => {});
  }
  tmpDirs = [];
});

function makeRun(overrides: Partial<SpecRun> = {}): SpecRun {
  return {
    runId: 'run-1',
    timestamp: '2026-02-15T00:00:00Z',
    resultPath: '.forge/results/2026-02-15T00:00:00Z',
    status: 'passed',
    costUsd: 0.5,
    durationSeconds: 60,
    numTurns: 10,
    verifyAttempts: 1,
    ...overrides,
  };
}

function makeEntry(overrides: Partial<SpecEntry> = {}): SpecEntry {
  return {
    spec: 'feature.md',
    status: 'passed',
    runs: [],
    source: 'file',
    createdAt: '2026-01-01T00:00:00Z',
    updatedAt: '2026-01-01T00:00:00Z',
    ...overrides,
  };
}

function makeManifest(specs: SpecEntry[] = []): SpecManifest {
  return { version: 1, specs };
}

function makeSummary(overrides: Partial<ForgeResult> = {}): ForgeResult {
  return {
    startedAt: '2026-01-01T00:00:00Z',
    completedAt: '2026-01-01T00:01:00Z',
    durationSeconds: 60,
    status: 'success',
    prompt: 'test prompt',
    model: 'sonnet',
    cwd: '/test',
    costUsd: 0.50,
    sessionId: 'sess-001',
    ...overrides,
  };
}

async function setupForge(dir: string, manifest?: SpecManifest): Promise<void> {
  const forgeDir = path.join(dir, '.forge');
  await fs.mkdir(forgeDir, { recursive: true });
  await fs.writeFile(
    path.join(forgeDir, 'specs.json'),
    JSON.stringify(manifest ?? makeManifest()),
  );
}

async function setupResults(
  dir: string,
  results: Array<{ ts: string; summary: ForgeResult }>,
): Promise<void> {
  const resultsDir = path.join(dir, '.forge', 'results');
  for (const { ts, summary } of results) {
    const runDir = path.join(resultsDir, ts);
    await fs.mkdir(runDir, { recursive: true });
    await fs.writeFile(path.join(runDir, 'summary.json'), JSON.stringify(summary));
  }
}

async function setupSession(
  dir: string,
  sessionId: string,
  opts?: { events?: string; streamLog?: string },
): Promise<void> {
  const sessionDir = path.join(dir, '.forge', 'sessions', sessionId);
  await fs.mkdir(sessionDir, { recursive: true });
  if (opts?.streamLog) {
    await fs.writeFile(path.join(sessionDir, 'stream.log'), opts.streamLog);
  }
  if (opts?.events) {
    await fs.writeFile(path.join(sessionDir, 'events.jsonl'), opts.events);
  }
}

