// ── Sessions list view ──────────────────────────────────────

describe('TUI: sessions list view', () => {
  test('sessions list populates from summary.json files', async () => {
    const dir = await makeTmpDir();
    await setupResults(dir, [
      { ts: '2026-01-01T00:00:00Z', summary: makeSummary({ sessionId: 's1', status: 'success' }) },
      { ts: '2026-01-02T00:00:00Z', summary: makeSummary({ sessionId: 's2', status: 'error_execution' }) },
    ]);

    // Read summaries back to verify data is available
    const resultsDir = path.join(dir, '.forge', 'results');
    const dirs = await fs.readdir(resultsDir);
    expect(dirs).toHaveLength(2);

    for (const d of dirs) {
      const summaryPath = path.join(resultsDir, d, 'summary.json');
      const raw = await fs.readFile(summaryPath, 'utf-8');
      const summary: ForgeResult = JSON.parse(raw);
      expect(summary.sessionId).toBeTruthy();
      expect(summary.status).toBeTruthy();
    }
  });

  test('latest-session.json indicates running session', async () => {
    const dir = await makeTmpDir();
    await fs.mkdir(path.join(dir, '.forge'), { recursive: true });
    const sessionId = 'running-sess';
    const logPath = path.join(dir, '.forge', 'sessions', sessionId, 'stream.log');
    await setupSession(dir, sessionId, { streamLog: 'session in progress...\n' });

    await fs.writeFile(
      path.join(dir, '.forge', 'latest-session.json'),
      JSON.stringify({ sessionId, logPath }),
    );

    const latest = JSON.parse(
      await fs.readFile(path.join(dir, '.forge', 'latest-session.json'), 'utf-8'),
    );
    expect(latest.sessionId).toBe(sessionId);
    expect(latest.logPath).toBe(logPath);
  });

  test('session row data: status, spec name, model, cost, duration', () => {
    const summary = makeSummary({
      status: 'success',
      specPath: 'specs/auth.md',
      model: 'opus',
      costUsd: 1.25,
      durationSeconds: 120,
    });

    // Verify all fields needed for session row display are present
    expect(summary.status).toBe('success');
    expect(summary.specPath).toBe('specs/auth.md');
    expect(summary.model).toBe('opus');
    expect(summary.costUsd).toBe(1.25);
    expect(summary.durationSeconds).toBe(120);
  });

  test('status icons: > running, + passed, x failed', () => {
    const icons: Record<string, string> = {
      running: '>',
      success: '+',
      error_execution: 'x',
      error_max_turns: 'x',
      error_budget: 'x',
    };

    expect(icons['running']).toBe('>');
    expect(icons['success']).toBe('+');
    expect(icons['error_execution']).toBe('x');
  });
});

// ── Session detail view (drill-in) ─────────────────────────

describe('TUI: session detail view', () => {
  test('events.jsonl provides structured event data for drill-in', async () => {
    const dir = await makeTmpDir();
    const sessionId = 'detail-sess';
    const events = [
      JSON.stringify({ type: 'session_start', timestamp: '2026-01-01T00:00:00Z', sessionId, model: 'sonnet', prompt: 'test' }),
      JSON.stringify({ type: 'text_delta', timestamp: '2026-01-01T00:00:01Z', content: 'Reasoning step 1' }),
      JSON.stringify({ type: 'tool_call_start', timestamp: '2026-01-01T00:00:02Z', toolName: 'Bash', input: { command: 'ls' } }),
      JSON.stringify({ type: 'tool_call_result', timestamp: '2026-01-01T00:00:03Z', toolName: 'Bash', output: 'file1.ts' }),
      JSON.stringify({ type: 'session_end', timestamp: '2026-01-01T00:01:00Z', durationSeconds: 60, status: 'success' }),
    ].join('\n');

    await setupSession(dir, sessionId, { events });

    const eventsPath = path.join(dir, '.forge', 'sessions', sessionId, 'events.jsonl');
    const content = await fs.readFile(eventsPath, 'utf-8');
    const parsed = content.split('\n').filter(l => l.trim()).map(l => JSON.parse(l));

    expect(parsed).toHaveLength(5);
    expect(parsed[0].type).toBe('session_start');
    // text_delta for agent reasoning
    expect(parsed[1].type).toBe('text_delta');
    expect(parsed[1].content).toBe('Reasoning step 1');
    // tool_call for tool activity blocks
    expect(parsed[2].type).toBe('tool_call_start');
    expect(parsed[2].toolName).toBe('Bash');
    expect(parsed[3].type).toBe('tool_call_result');
    expect(parsed[3].output).toBe('file1.ts');
  });

  test('eventsPath derived from logPath by replacing stream.log', () => {
    const logPath = '/repo/.forge/sessions/abc/stream.log';
    const eventsPath = logPath.replace(/stream\.log$/, 'events.jsonl');
    expect(eventsPath).toBe('/repo/.forge/sessions/abc/events.jsonl');
  });
});

// ── Specs list view ─────────────────────────────────────────

describe('TUI: specs list view', () => {
  test('loads manifest with loadManifest()', async () => {
    const dir = await makeTmpDir();
    const manifest = makeManifest([
      makeEntry({ spec: 'auth/login.md', status: 'passed' }),
      makeEntry({ spec: 'auth/oauth.md', status: 'pending' }),
      makeEntry({ spec: 'db/migrate.md', status: 'failed' }),
    ]);
    await setupForge(dir, manifest);

    const loaded = await loadManifest(dir);
    expect(loaded.specs).toHaveLength(3);
  });

  test('entries grouped by parent directory', () => {
    const entries = [
      makeEntry({ spec: 'auth/login.md' }),
      makeEntry({ spec: 'auth/oauth.md' }),
      makeEntry({ spec: 'db/migrate.md' }),
      makeEntry({ spec: 'db/seed.md' }),
      makeEntry({ spec: 'root-spec.md' }),
    ];

    // Group by directory
    const groups = new Map<string, SpecEntry[]>();
    for (const entry of entries) {
      const dir = path.dirname(entry.spec);
      const key = dir === '.' ? 'specs/' : dir + '/';
      if (!groups.has(key)) groups.set(key, []);
      groups.get(key)!.push(entry);
    }

    expect(groups.size).toBe(3);
    expect(groups.get('auth/')!).toHaveLength(2);
    expect(groups.get('db/')!).toHaveLength(2);
    expect(groups.get('specs/')!).toHaveLength(1);
  });

  test('status icon mapping: + passed, x failed, - pending', () => {
    const iconMap: Record<string, string> = {
      passed: '+',
      failed: 'x',
      pending: '-',
      running: '>',
    };

    expect(iconMap['passed']).toBe('+');
    expect(iconMap['failed']).toBe('x');
    expect(iconMap['pending']).toBe('-');
    expect(iconMap['running']).toBe('>');
  });

  test('total cost per spec calculated from runs', () => {
    const entry = makeEntry({
      runs: [
        makeRun({ costUsd: 0.50 }),
        makeRun({ costUsd: 1.25 }),
        makeRun({ costUsd: 0.75 }),
      ],
    });
    const totalCost = entry.runs.reduce((s, r) => s + (r.costUsd ?? 0), 0);
    expect(totalCost).toBeCloseTo(2.50, 2);
  });

  test('total duration per spec calculated from runs', () => {
    const entry = makeEntry({
      runs: [
        makeRun({ durationSeconds: 60 }),
        makeRun({ durationSeconds: 120 }),
        makeRun({ durationSeconds: 30 }),
      ],
    });
    const totalDuration = entry.runs.reduce((s, r) => s + r.durationSeconds, 0);
    expect(totalDuration).toBe(210);
  });

  test('empty manifest shows no specs', async () => {
    const dir = await makeTmpDir();
    await setupForge(dir, makeManifest([]));

    const loaded = await loadManifest(dir);
    expect(loaded.specs).toHaveLength(0);
  });

  test('loadManifest returns empty for missing file', async () => {
    const dir = await makeTmpDir();
    // No .forge directory at all
    const loaded = await loadManifest(dir);
    expect(loaded.specs).toHaveLength(0);
  });
});

// ── Spec detail view ────────────────────────────────────────

describe('TUI: spec detail view', () => {
  test('spec entry has all fields needed for detail view', () => {
    const entry = makeEntry({
      spec: 'auth/login.md',
      status: 'passed',
      source: 'file',
      createdAt: '2026-01-01T00:00:00Z',
      updatedAt: '2026-03-01T00:00:00Z',
      runs: [
        makeRun({ runId: 'r1', status: 'failed', costUsd: 0.30, durationSeconds: 45, numTurns: 5, verifyAttempts: 2 }),
        makeRun({ runId: 'r2', status: 'passed', costUsd: 0.50, durationSeconds: 60, numTurns: 8, verifyAttempts: 1 }),
      ],
    });

    expect(entry.spec).toBe('auth/login.md');
    expect(entry.status).toBe('passed');
    expect(entry.source).toBe('file');
    expect(entry.createdAt).toBeTruthy();
    expect(entry.updatedAt).toBeTruthy();
    expect(entry.runs).toHaveLength(2);
  });

  test('run history sorted newest-first', () => {
    const runs = [
      makeRun({ runId: 'r1', timestamp: '2026-01-01T00:00:00Z' }),
      makeRun({ runId: 'r3', timestamp: '2026-03-01T00:00:00Z' }),
      makeRun({ runId: 'r2', timestamp: '2026-02-01T00:00:00Z' }),
    ];
    const sorted = [...runs].sort((a, b) => b.timestamp.localeCompare(a.timestamp));

    expect(sorted[0].runId).toBe('r3');
    expect(sorted[1].runId).toBe('r2');
    expect(sorted[2].runId).toBe('r1');
  });

  test('run has all fields for display', () => {
    const run = makeRun({
      runId: 'run-abc',
      timestamp: '2026-03-11T10:00:00Z',
      status: 'passed',
      costUsd: 1.50,
      durationSeconds: 120,
      numTurns: 15,
      verifyAttempts: 2,
      resultPath: '.forge/results/2026-03-11T10:00:00Z',
    });

    expect(run.runId).toBe('run-abc');
    expect(run.timestamp).toBeTruthy();
    expect(run.status).toBe('passed');
    expect(run.costUsd).toBe(1.50);
    expect(run.durationSeconds).toBe(120);
    expect(run.numTurns).toBe(15);
    expect(run.verifyAttempts).toBe(2);
    expect(run.resultPath).toBeTruthy();
  });

  test('empty runs shows no history', () => {
    const entry = makeEntry({ runs: [] });
    expect(entry.runs).toHaveLength(0);
  });

  test('session can be derived from run resultPath', () => {
    const run = makeRun({ resultPath: '.forge/results/2026-03-11T10:00:00Z' });
    // The last segment of resultPath can serve as a session identifier
    const segments = run.resultPath.split('/');
    const lastSegment = segments[segments.length - 1];
    expect(lastSegment).toBe('2026-03-11T10:00:00Z');
  });
});

